// DATA ATUAL

var agora = new Date();
var ano = agora.getFullYear();

// Dia do ano
var inicioAno = new Date(ano, 0, 0);
var diff = agora - inicioAno;
var umDia = 1000 * 60 * 60 * 24;
var N = Math.floor(diff / umDia);

// Hora atual decimal
var horaAtual = agora.getHours() +
                agora.getMinutes()/60 +
                agora.getSeconds()/3600;


// FUNÇÕES AUXILIARES

function rad(g) { return g * Math.PI / 180; }
function deg(r) { return r * 180 / Math.PI; }


// DECLINAÇÃO SOLAR

var decl = 23.45 * Math.sin(rad((360/365) * (284 + N)));

// ÂNGULO HORÁRIO
var cosW = -Math.tan(rad(lat)) * Math.tan(rad(decl));

// Correção matemática
if (cosW > 1) cosW = 1;
if (cosW < -1) cosW = -1;

var W = deg(Math.acos(cosW));

// Duração real do dia
var duracaoDia = (2 * W) / 15;


// AJUSTE POR LONGITUDE (Brasil UTC-3)

var fuso = -3;
var meridianoCentral = fuso * 15;
var correcaoLongitude = (lon - meridianoCentral) / 15;

var meioDiaSolar = 12 - correcaoLongitude;

var nascerSol = meioDiaSolar - duracaoDia/2;
var porSol = meioDiaSolar + duracaoDia/2;


// HORAS SOLARES DECORRIDAS

var horasSolares;

if (horaAtual <= nascerSol) {
    horasSolares = 0;
} 
else if (horaAtual >= porSol) {
    horasSolares = duracaoDia;
} 
else {
    horasSolares = horaAtual - nascerSol;
}

// Proteção
if (horasSolares <= 0) return 0;


// CÁLCULO DO FC

var FC = (energia / (capacity * horasSolares)) * 100;


// CLAMP DE SEGURANÇA (0% a 100%)

if (isNaN(FC) || !isFinite(FC)) {
    return 0;
}

if (FC > 100) FC = 100;
if (FC < 0) FC = 0;

return FC;

